object ConfigXmlParser {

  def createSecureSAXParser(): SAXParserFactory = {
    val factory = SAXParserFactory.newInstance()
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.setNamespaceAware(false)
    factory
  }

  def parseXmlSecurely(xmlString: String): Try[Elem] = {
    Try {
      val factory = createSecureSAXParser()
      val parser = factory.newSAXParser()
      XML.withSAXParser(parser).loadString(xmlString)
    }
  }

  def extractSettings(xmlString: String): ParseResult = {
    parseXmlSecurely(xmlString) match {
      case Success(rootElem) =>
        try {
          val settings = extractFromElement(rootElem, None)
          ParseResult(success = true, settings = settings, errors = List.empty)
        } catch {
          case e: Exception =>
            ParseResult(success = false, settings = List.empty, errors = List(s"Error extracting settings: ${e.getMessage}"))
        }
      case Failure(e) =>
        ParseResult(success = false, settings = List.empty, errors = List(s"XML parsing error: ${e.getMessage}"))
    }
  }

  def extractFromElement(elem: Elem, currentSection: Option[String]): List[ConfigSetting] = {
    elem.label match {
      case "configuration" | "config" =>
        elem.child.collect {
          case e: Elem => extractFromElement(e, currentSection)
        }.flatten.toList

      case "section" | "group" =>
        val sectionName = (elem \ "@name").text match {
          case "" => (elem \ "@id").text match {
            case "" => elem.label
            case id => id
          }
          case name => name
        }
        val fullSection = currentSection.map(s => s"$s.$sectionName").getOrElse(sectionName)
        elem.child.collect {
          case e: Elem => extractFromElement(e, Some(fullSection))
        }.flatten.toList

      case "setting" | "property" | "param" | "entry" =>
        val key = (elem \ "@name").text match {
          case "" => (elem \ "@key").text match {
            case "" => (elem \ "@id").text
            case k => k
          }
          case n => n
        }
        val value = (elem \ "@value").text match {
          case "" => elem.text.trim
          case v => v
        }
        if (key.nonEmpty) {
          List(ConfigSetting(key = key, value = value, section = currentSection))
        } else {
          List.empty
        }

      case "include" =>
        val refId = (elem \ "@ref").text
        if (refId.nonEmpty) {
          List(ConfigSetting(key = s"_include_ref", value = refId, section = currentSection))
        } else {
          List.empty
        }

      case other =>
        val hasChildren = elem.child.exists(_.isInstanceOf[Elem])
        if (hasChildren) {
          val sectionName = (elem \ "@name").text match {
            case "" => other
            case n => n
          }
          val fullSection = currentSection.map(s => s"$s.$sectionName").getOrElse(sectionName)
          elem.child.collect {
            case e: Elem => extractFromElement(e, Some(fullSection))
          }.flatten.toList
        } else {
          val value = (elem \ "@value").text match {
            case "" => elem.text.trim
            case v => v
          }
          if (value.nonEmpty) {
            List(ConfigSetting(key = other, value = value, section = currentSection))
          } else {
            List.empty
          }
        }
    }
  }

  def resolveReferences(settings: List[ConfigSetting]): List[ConfigSetting] = {
    val settingsMap: Map[String, String] = settings
      .filter(_.key != "_include_ref")
      .map { s =>
        val fullKey = s.section.map(sec => s"$sec.${s.key}").getOrElse(s.key)
        fullKey -> s.value
      }.toMap

    settings.map { setting =>
      val resolvedValue = resolveVariables(setting.value, settingsMap)
      setting.copy(value = resolvedValue)
    }
  }

  private def resolveVariables(value: String, settingsMap: Map[String, String]): String = {
    val pattern = """\$\{([^}]+)\}""".r
    var result = value
    var iterations = 0
    val maxIterations = 10

    while (pattern.findFirstIn(result).isDefined && iterations < maxIterations) {
      result = pattern.replaceAllIn(result, m => {
        val ref = m.group(1)
        java.util.regex.Matcher.quoteReplacement(settingsMap.getOrElse(ref, m.matched))
      })
      iterations += 1
    }
    result
  }
}

object ConfigManagementService extends App {
  import JsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management")
  import system.dispatcher

  val route: Route = {
    pathPrefix("api" / "config") {
      path("parse") {
        post {
          entity(as[ParseRequest]) { request =>
            val result = ConfigXmlParser.extractSettings(request.xml)
            val resolvedResult = result.copy(
              settings = ConfigXmlParser.resolveReferences(result.settings)
            )
            complete(resolvedResult)
          }
        }
      } ~
      path("parse" / "raw") {
        post {
          entity(as[String]) { xmlString =>
            val result = ConfigXmlParser.extractSettings(xmlString)
            val resolvedResult = result.copy(
              settings = ConfigXmlParser.resolveReferences(result.settings)
            )
            complete(resolvedResult)
          }
        }
      } ~
      path("validate") {
        post {
          entity(as[ParseRequest]) { request =>
            val parseAttempt = ConfigXmlParser.parseXmlSecurely(request.xml)
            parseAttempt match {
              case Success(_) =>
                complete(JsObject(
                  "valid" -> JsTrue,
                  "message" -> JsString("XML configuration is well-formed and valid")
                ))
              case Failure(e) =>
                complete(StatusCodes.BadRequest, JsObject(
                  "valid" -> JsFalse,
                  "message" -> JsString(s"Invalid XML: ${e.getMessage}")
                ))
            }
          }
        }
      } ~
      path("settings" / Segment) { section =>
        post {
          entity(as[ParseRequest]) { request =>
            val result = ConfigXmlParser.extractSettings(request.xml)
            val resolved = ConfigXmlParser.resolveReferences(result.settings)
            val filtered = resolved.filter(_.section.exists(_.startsWith(section)))
            complete(result.copy(settings = filtered))
          }
        }
      } ~
      path("health") {
        get {
          complete(JsObject(
            "status" -> JsString("healthy"),
            "service" -> JsString("config-management"),
            "version" -> JsString("1.0.0")
          ))
        }
      }
    }
  }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(binding) =>
      println(s"Configuration Management Service running at http://${binding.localAddress.getHostString}:${binding.localAddress.getPort}/")
    case Failure(ex) =>
      println(s"Failed to bind HTTP server: ${ex.getMessage}")
      system.terminate()
  }
}